INSERT INTO public.exercise_library (organization_id, created_by, name, category, subcategory, discipline, muscle_groups, equipment_required, hyrox_station, difficulty_level, description, coaching_cues, is_approved, source)
VALUES
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Ski Erg', 'hyrox', 'station', 'skierg', ARRAY['lats','shoulders','core','triceps'], ARRAY['ski_erg'], 'Ski Erg', 'intermediate', '1000m on the Ski Erg. Full-body pulling movement emphasising lat engagement and core bracing.', 'Drive arms down explosively. Hinge at hips. Keep core tight. Rhythm over power.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Sled Push', 'hyrox', 'station', 'hyrox_station', ARRAY['quads','glutes','core','shoulders'], ARRAY['sled'], 'Sled Push', 'hard', '50m sled push. Explosive lower body drive with forward lean.', 'Low hips, full foot contact. Short powerful strides. Eyes down. Do not let hips rise.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Sled Pull', 'hyrox', 'station', 'hyrox_station', ARRAY['hamstrings','glutes','back','core'], ARRAY['sled','rope'], 'Sled Pull', 'hard', '50m sled pull with rope. Hip hinge dominant. Posterior chain loaded.', 'Full hip extension each rep. Keep rope taut. Step back quickly between pulls.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Burpee Broad Jump', 'hyrox', 'station', 'hyrox_station', ARRAY['full_body','quads','chest','core'], ARRAY['none'], 'Burpee Broad Jump', 'hard', '80 reps. Chest to floor burpee followed by a two-foot broad jump forward.', 'Chest fully contacts floor. Explosive jump. Land soft with knees bent. Consistent pace over sprint.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Rowing', 'hyrox', 'station', 'rowing', ARRAY['back','legs','core','arms'], ARRAY['rowing_erg'], 'Rowing', 'intermediate', '1000m on the rowing erg. Drive with legs first, then lean, then arms.', 'Drive legs, open hips, pull to lower chest. Recovery in reverse order. Catch with shins vertical.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Farmers Carry', 'hyrox', 'station', 'hyrox_station', ARRAY['forearms','traps','core','glutes'], ARRAY['kettlebells','dumbbells'], 'Farmers Carry', 'intermediate', '200m carry. Bilateral loaded carry demanding grip and trunk stability.', 'Tall posture. Shoulders packed. Small quick steps. No swinging. Breathe rhythmically.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Sandbag Lunge', 'hyrox', 'station', 'hyrox_station', ARRAY['quads','glutes','core'], ARRAY['sandbag'], 'Sandbag Lunge', 'hard', '100m walking lunge with sandbag. High demand on quad and glute endurance.', 'Bag on one shoulder or across traps. 90-degree knee bend. Full extension at top. Consistent stride length.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Wall Ball', 'hyrox', 'station', 'hyrox_station', ARRAY['quads','shoulders','core'], ARRAY['wall_ball'], 'Wall Ball', 'intermediate', '100 reps. Squat-to-throw movement. Full depth squat, explosive triple extension.', 'Full squat depth. Explode up, use legs to launch ball. Catch high on chest. Fluid rhythm.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Barbell Back Squat', 'strength', 'lower_body', 'strength', ARRAY['quads','glutes','hamstrings','core'], ARRAY['barbell','rack'], NULL, 'intermediate', 'Compound lower body movement. Primary hypertrophy and strength driver.', 'Bar on traps. Hips back and down. Knees track toes. Full depth. Drive through heels.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Romanian Deadlift', 'strength', 'lower_body', 'strength', ARRAY['hamstrings','glutes','lower_back'], ARRAY['barbell','dumbbells'], NULL, 'intermediate', 'Hinge pattern targeting posterior chain. Key for Sled Pull and Farmers Carry strength.', 'Neutral spine. Slight knee bend. Push hips back. Feel hamstring stretch. Drive hips forward.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Bulgarian Split Squat', 'strength', 'lower_body', 'strength', ARRAY['quads','glutes','hip_flexors'], ARRAY['dumbbells','barbell','bench'], NULL, 'intermediate', 'Unilateral leg strength. Corrects imbalances. High HYROX transfer.', 'Back foot elevated. Front shin vertical. Drop straight down. Full range. Control descent.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Nordic Hamstring Curl', 'prehab', 'lower_body', 'prehab', ARRAY['hamstrings'], ARRAY['partner','machine'], NULL, 'hard', 'Eccentric hamstring loading. Critical for hamstring tendinopathy management and injury prevention.', 'Kneel, ankles held. Lower torso slowly with hamstrings only. Catch with hands. Pull back up.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Single-Leg Romanian Deadlift', 'strength', 'lower_body', 'strength', ARRAY['hamstrings','glutes','core'], ARRAY['dumbbells','kettlebell'], NULL, 'intermediate', 'Unilateral hinge. Balance and posterior chain. High value for Leandro given scoliosis/leg length discrepancy.', 'Planted leg soft bend. Hip hinge. Free leg drives back. Neutral spine throughout.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Hip Thrust', 'strength', 'lower_body', 'strength', ARRAY['glutes','hamstrings'], ARRAY['barbell','bench'], NULL, 'beginner', 'Glute isolation in terminal extension. Key for bursitis-friendly glute loading.', 'Shoulder blades on bench. Drive through heels. Full hip extension. Squeeze glutes at top.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Step-Up', 'strength', 'lower_body', 'strength', ARRAY['quads','glutes'], ARRAY['box','dumbbells'], NULL, 'beginner', 'Unilateral loading. Sandbag Lunge transfer.', 'Drive through heel of working leg. No push-off from trailing foot. Control descent.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Copenhagen Plank', 'prehab', 'hip_adductor', 'prehab', ARRAY['hip_adductors','core','glutes'], ARRAY['bench'], NULL, 'intermediate', 'Hip adductor and core stability. Key for pelvic drop correction in running.', 'Top foot on bench. Bottom leg off ground. Hold plank. Progress to reps lifting bottom leg.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Dumbbell Row', 'strength', 'upper_body', 'strength', ARRAY['lats','rhomboids','biceps'], ARRAY['dumbbell','bench'], NULL, 'beginner', 'Horizontal pull. Ski Erg and Sled Pull transfer.', 'Chest supported or single arm. Pull elbow past torso. Full retraction. Control descent.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Overhead Press', 'strength', 'upper_body', 'strength', ARRAY['shoulders','triceps','core'], ARRAY['barbell','dumbbells'], NULL, 'intermediate', 'Vertical push. Shoulder stability for Wall Ball and Ski Erg.', 'Start at collarbones. Press vertical. Glutes and core tight. Lockout elbows.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Plank', 'prehab', 'core', 'prehab', ARRAY['core','shoulders','glutes'], ARRAY['none'], NULL, 'beginner', 'Core anti-extension. Foundation for all Hyrox stations.', 'Neutral spine. Squeeze glutes. Do not let hips sag or rise. Breathe diaphragmatically.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Dead Bug', 'prehab', 'core', 'prehab', ARRAY['core','hip_flexors'], ARRAY['none'], NULL, 'beginner', 'Core coordination and anti-extension. Key for L5-S1 management.', 'Lower back pressed to floor. Opposite arm and leg extend. Exhale on movement. Slow and controlled.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Lateral Band Walk', 'prehab', 'glutes', 'prehab', ARRAY['glutes','hip_abductors'], ARRAY['resistance_band'], NULL, 'beginner', 'Glute med activation. Corrects pelvic drop during single-leg support in running.', 'Band above knees. Hip width stance. Step out, bring feet together. Keep toes forward.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'A-Skip', 'run_drill', 'cadence', 'run', ARRAY['hip_flexors','calves','core'], ARRAY['none'], NULL, 'beginner', 'Running drill for cadence and dorsiflexion. 2x20m.', 'High knee drive. Foot strikes under hip. Arm swing opposite. Tall posture.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'B-Skip', 'run_drill', 'cadence', 'run', ARRAY['hamstrings','hip_flexors'], ARRAY['none'], NULL, 'beginner', 'Running drill extending A-skip with active hamstring pull. 2x20m.', 'High knee, then extend and pull foot down and back. Pawing action. Stay tall.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'High Knees', 'run_drill', 'cadence', 'run', ARRAY['hip_flexors','core'], ARRAY['none'], NULL, 'beginner', 'Cadence and knee drive drill. 2x20m or 20 seconds.', 'Drive knees to hip height. Fast arm swing. Stay on balls of feet. Minimal ground contact.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Butt Kicks', 'run_drill', 'cadence', 'run', ARRAY['hamstrings','calves'], ARRAY['none'], NULL, 'beginner', 'Hamstring activation and cadence drill. 2x20m.', 'Heel to glute each step. Stay upright. Arms drive. Land on forefoot.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Running Strides', 'run_drill', 'speed', 'run', ARRAY['full_body'], ARRAY['none'], NULL, 'intermediate', '3-4 x 80-100m progressive accelerations. Build to 90% effort.', 'Start easy, build to fast. Relaxed form. Full recovery between strides.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'IC4 Zone 2 Ride', 'conditioning', 'aerobic_base', 'bike', ARRAY['quads','glutes','cardiovascular'], ARRAY['bike_trainer'], NULL, 'easy', 'Steady state Zone 2 cycling. HR 130-140. Resistance R21-23 on Schwinn IC4.', 'Resistance R21-23. HR must stay 130-140. Conversational pace. Cadence 80-90 rpm.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'IC4 VO2max Intervals', 'conditioning', 'vo2max', 'bike', ARRAY['full_body','cardiovascular'], ARRAY['bike_trainer'], NULL, 'hard', 'Norwegian 4x4 on IC4. 4 min at R30-42, HR 178-188. 3 min recovery at R15-18.', 'Build HR through first 60-90s. Hold 90-95% HRmax for 4 min. Recovery at easy resistance until HR drops below 130.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'Norwegian 4x4 Run', 'conditioning', 'vo2max', 'run', ARRAY['full_body','cardiovascular'], ARRAY['none'], NULL, 'hard', '4 x 4 min at 90-95% HRmax, 3 min active recovery. Non-negotiable weekly anchor.', 'Target HR 178-188 during work intervals. Recovery 6:00-6:30/km pace. 4 repeats. Warm up 10 min.', true, 'seed'),
  ('47d03850-eb38-4a8d-8803-580d710773a8', 'df580f27-a8ab-4475-b695-a382028cc4a9', 'HYROX Race Simulation', 'conditioning', 'hyrox_specific', 'hyrox_station', ARRAY['full_body','cardiovascular'], ARRAY['sled','rowing_erg','wall_ball','sandbag','kettlebells'], NULL, 'hard', 'Full or partial race simulation. 1km run + station + repeat. Practice transitions and electrolyte protocol.', 'Race pace per station. Sip electrolytes after Sled Push before Run 3. Maintain technique under fatigue.', true, 'seed')
